import React, { useEffect, useState } from 'react';
import * as C from './style';
/* import {
    FaRegArrowAltCircleUp,
    FaRegArrowAltCircleDown,
    FaTrash,
} from 'react-icons/fa'; */

function BoxPedido({ pedido, produtos }) {

    if(typeof(pedido.carrinho) === "string") pedido.carrinho = JSON.parse(pedido.carrinho)
    return (
        <C.Item>
            <C.Nome>
                {pedido.carrinho.pontoCarne !== "" && (
                    <C.PontoCarne>
                        <p>
                            {pedido.carrinho.pontoCarne}
                        </p>
                    </C.PontoCarne>
                )}
                <p>
                    {pedido.carrinho.qtd}{pedido.carrinho.carnes >= 2 ? 'x'+pedido.carrinho.carnes : ''}  {pedido.nome}
                </p>
            </C.Nome>
            <C.BoxAdc qtdAdc={pedido.carrinho.adc.length}>
                {pedido.carrinho.adc.map( (e, index) => {
                   return (<C.Adc key={index}>
                        <p>
                            {'+' + e}
                        </p>
                    </C.Adc>)
                })}
            </C.BoxAdc>
            <C.Obs>
                <p>{pedido.obs}</p>
            </C.Obs>
        </C.Item>
    )
}

export default BoxPedido
